form:Form.form:Scripts:
		function toggleAllVacaciones(){
	if(Ctrl("all_Vacaciones").GetXValue()!=1)
	{
		Ctrl("e_cant_dias").SetXValue(0);
		Ctrl("l_habiles").SetXValue(0);
		Ctrl("f_ant_rec_vac").SetXValue(0);
		Ctrl("e_max_dias_sol_vac").SetXValue(0);
		Ctrl("e_max_dias_vac_ant").SetXValue(0); 
		Ctrl("oi_grupo_legajo").SetXValue(0);
	}                     
	else
	{
		Ctrl("e_cant_dias").SetXValue(1);
		Ctrl("l_habiles").SetXValue(1);
		Ctrl("f_ant_rec_vac").SetXValue(1);
		Ctrl("e_max_dias_sol_vac").SetXValue(1);
		Ctrl("e_max_dias_vac_ant").SetXValue(1);
		Ctrl("oi_grupo_legajo").SetXValue(1);
	}

}        

function toggleAllMatrizVacaciones(){
	if(Ctrl("all_MatrizVacaciones").GetXValue()!=1)
	{
		Ctrl("e_min_dias_trab").SetXValue(0);
		Ctrl("e_min_dias_ant_vac").SetXValue(0);
		Ctrl("oi_matriz_vac").SetXValue(0);
	}                     
	else
	{
		Ctrl("e_min_dias_trab").SetXValue(1);
		Ctrl("e_min_dias_ant_vac").SetXValue(1);
		Ctrl("oi_matriz_vac").SetXValue(1);
	}

}
